def now_ms() -> int:
    return int(time.time() * 1000)


def jdump(obj: Any) -> str:
    return json.dumps(obj, separators=(",", ":"), ensure_ascii=False)


def safe_int(x, default=None):
    try:
        return int(x)
    except Exception:
        return default


@dataclass
class Item:
    item_id: str
    item_type: str
    meta: Dict[str, Any] = field(default_factory=dict)

    def to_dict(self) -> Dict[str, Any]:
        return {"item_id": self.item_id, "item_type": self.item_type, "meta": self.meta}


@dataclass
class Player:
    player_id: str
    name: str
    ws: WebSocketServerProtocol
    connected_at: int = field(default_factory=now_ms)
    inventory: Set[str] = field(default_factory=set)
    balance: int = 0

    def to_public(self) -> Dict[str, Any]:
        return {"player_id": self.player_id, "name": self.name}


class InventoryLedger:
    def __init__(self):
        self.items: Dict[str, Item] = {}
        self.owner: Dict[str, str] = {}  # item_id -> player_id
        self._lock = asyncio.Lock()
        self._player_locks: Dict[str, asyncio.Lock] = {}
        self._item_locks: Dict[str, asyncio.Lock] = {}

    def _get_player_lock(self, player_id: str) -> asyncio.Lock:
        lock = self._player_locks.get(player_id)
        if lock is None:
            lock = asyncio.Lock()
            self._player_locks[player_id] = lock
        return lock

    def _get_item_lock(self, item_id: str) -> asyncio.Lock:
        lock = self._item_locks.get(item_id)
        if lock is None:
            lock = asyncio.Lock()
            self._item_locks[item_id] = lock
        return lock

    async def ensure_item(self, item: Item, owner_player_id: Optional[str] = None) -> None:
        async with self._lock:
            if item.item_id not in self.items:
                self.items[item.item_id] = item
                if owner_player_id is not None:
                    self.owner[item.item_id] = owner_player_id

    async def mint_to_player(self, item_type: str, meta: Dict[str, Any], player_id: str) -> Item:
        item = Item(item_id=str(uuid.uuid4()), item_type=item_type, meta=meta or {})
        async with self._lock:
            self.items[item.item_id] = item
            self.owner[item.item_id] = player_id
        return item

    async def get_owner(self, item_id: str) -> Optional[str]:
        async with self._lock:
            return self.owner.get(item_id)

    async def transfer_item(self, item_id: str, from_player: str, to_player: str) -> Tuple[bool, str]:
        if from_player == to_player:
            return False, "same_player"

        item_lock = self._get_item_lock(item_id)
        async with item_lock:
            async with self._lock:
                if item_id not in self.items:
                    return False, "item_not_found"
                current_owner = self.owner.get(item_id)
                if current_owner != from_player:
                    return False, "not_owner"
                self.owner[item_id] = to_player
                return True, "ok"

    async def atomic_transfer_items(self, item_ids: List[str], from_player: str, to_player: str) -> Tuple[bool, str]:
        if from_player == to_player:
            return False, "same_player"
        if not item_ids:
            return True, "ok"

        locks = [self._get_item_lock(i) for i in item_ids]
        unique = {}
        for i, lk in zip(item_ids, locks):
            unique[i] = lk
        ordered = sorted(unique.items(), key=lambda kv: kv[0])
        acquired = []
        try:
            for _, lk in ordered:
                await lk.acquire()
                acquired.append(lk)
            async with self._lock:
                for iid in item_ids:
                    if iid not in self.items:
                        return False, f"item_not_found:{iid}"
                    if self.owner.get(iid) != from_player:
                        return False, f"not_owner:{iid}"
                for iid in item_ids:
                    self.owner[iid] = to_player
                return True, "ok"
        finally:
            for lk in reversed(acquired):
                lk.release()

    async def snapshot_player_inventory(self, player_id: str) -> List[Dict[str, Any]]:
        async with self._lock:
            item_ids = [iid for iid, owner in self.owner.items() if owner == player_id]
            return [self.items[iid].to_dict() for iid in item_ids if iid in self.items]


class GameServer:
    def __init__(self):
        self.players_by_ws: Dict[WebSocketServerProtocol, Player] = {}
        self.players_by_id: Dict[str, Player] = {}
        self.ledger = InventoryLedger()
        self._broadcast_lock = asyncio.Lock()
        self._trade_lock = asyncio.Lock()  # serialize trade-request creation if needed

    async def send(self, ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> None:
        if ws.closed:
            return
        try:
            await ws.send(jdump(msg))
        except Exception:
            pass

    async def send_player(self, player_id: str, msg: Dict[str, Any]) -> None:
        p = self.players_by_id.get(player_id)
        if not p:
            return
        await self.send(p.ws, msg)

    async def broadcast(self, msg: Dict[str, Any]) -> None:
        payload = jdump(msg)
        async with self._broadcast_lock:
            conns = list(self.players_by_ws.keys())
        for ws in conns:
            if ws.closed:
                continue
            try:
                await ws.send(payload)
            except Exception:
                pass

    async def register(self, ws: WebSocketServerProtocol, name: str) -> Player:
        player_id = str(uuid.uuid4())
        p = Player(player_id=player_id, name=name[:32], ws=ws)
        self.players_by_ws[ws] = p
        self.players_by_id[player_id] = p
        await self.send(ws, {"type": "welcome", "player_id": player_id, "name": p.name, "ts": now_ms()})
        inv = await self.ledger.snapshot_player_inventory(player_id)
        await self.send(ws, {"type": "inventory", "player_id": player_id, "items": inv, "ts": now_ms()})
        await self.broadcast({"type": "player_joined", "player": p.to_public(), "ts": now_ms()})
        return p

    async def unregister(self, ws: WebSocketServerProtocol) -> None:
        p = self.players_by_ws.pop(ws, None)
        if not p:
            return
        self.players_by_id.pop(p.player_id, None)
        await self.broadcast({"type": "player_left", "player_id": p.player_id, "ts": now_ms()})

    async def handle_msg(self, ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> None:
        mtype = msg.get("type")
        if mtype == "login":
            name = str(msg.get("name") or "Player")
            if ws in self.players_by_ws:
                await self.send(ws, {"type": "error", "error": "already_logged_in", "ts": now_ms()})
                return
            p = await self.register(ws, name)
            if msg.get("starter_pack"):
                await self._give_starter_pack(p.player_id)
            return

        p = self.players_by_ws.get(ws)
        if not p:
            await self.send(ws, {"type": "error", "error": "not_logged_in", "ts": now_ms()})
            return

        if mtype == "ping":
            await self.send(ws, {"type": "pong", "ts": now_ms()})
            return

        if mtype == "list_players":
            players = [pl.to_public() for pl in self.players_by_id.values()]
            await self.send(ws, {"type": "players", "players": players, "ts": now_ms()})
            return

        if mtype == "inventory_get":
            inv = await self.ledger.snapshot_player_inventory(p.player_id)
            await self.send(ws, {"type": "inventory", "player_id": p.player_id, "items": inv, "ts": now_ms()})
            return

        if mtype == "mint":
            item_type = str(msg.get("item_type") or "unknown")
            meta = msg.get("meta") or {}
            if not isinstance(meta, dict):
                meta = {}
            item = await self.ledger.mint_to_player(item_type, meta, p.player_id)
            await self.send(ws, {"type": "minted", "item": item.to_dict(), "owner": p.player_id, "ts": now_ms()})
            await self._push_inventory_update([p.player_id])
            return

        if mtype == "transfer_item":
            await self._handle_transfer_item(p, msg)
            return

        if mtype == "trade_items":
            await self._handle_trade_items(p, msg)
            return

        await self.send(ws, {"type": "error", "error": "unknown_message_type", "ts": now_ms(), "detail": mtype})

    async def _push_inventory_update(self, player_ids: List[str]) -> None:
        for pid in set(player_ids):
            inv = await self.ledger.snapshot_player_inventory(pid)
            await self.send_player(pid, {"type": "inventory", "player_id": pid, "items": inv, "ts": now_ms()})

    async def _give_starter_pack(self, player_id: str) -> None:
        for _ in range(3):
            await self.ledger.mint_to_player("potion", {"heal": 25}, player_id)
        await self.ledger.mint_to_player("sword", {"atk": 5}, player_id)
        await self._push_inventory_update([player_id])

    async def _handle_transfer_item(self, p: Player, msg: Dict[str, Any]) -> None:
        item_id = str(msg.get("item_id") or "")
        to_player = str(msg.get("to_player_id") or "")
        req_id = str(msg.get("req_id") or str(uuid.uuid4()))

        if not item_id or not to_player:
            await self.send(p.ws, {"type": "transfer_result", "req_id": req_id, "ok": False, "error": "bad_request", "ts": now_ms()})
            return
        if to_player not in self.players_by_id:
            await self.send(p.ws, {"type": "transfer_result", "req_id": req_id, "ok": False, "error": "target_not_online", "ts": now_ms()})
            return

        ok, reason = await self.ledger.transfer_item(item_id, p.player_id, to_player)
        if not ok:
            await self.send(p.ws, {"type": "transfer_result", "req_id": req_id, "ok": False, "error": reason, "ts": now_ms(), "item_id": item_id})
            return

        await self.send(p.ws, {"type": "transfer_result", "req_id": req_id, "ok": True, "ts": now_ms(), "item_id": item_id, "to_player_id": to_player})
        await self.send_player(to_player, {"type": "item_received", "item_id": item_id, "from_player_id": p.player_id, "ts": now_ms()})
        await self._push_inventory_update([p.player_id, to_player])

    async def _handle_trade_items(self, p: Player, msg: Dict[str, Any]) -> None:
        req_id = str(msg.get("req_id") or str(uuid.uuid4()))
        to_player = str(msg.get("to_player_id") or "")
        give_item_ids = msg.get("give_item_ids") or []
        take_item_ids = msg.get("take_item_ids") or []

        if not isinstance(give_item_ids, list) or not isinstance(take_item_ids, list):
            await self.send(p.ws, {"type": "trade_result", "req_id": req_id, "ok": False, "error": "bad_request", "ts": now_ms()})
            return

        give_item_ids = [str(x) for x in give_item_ids if str(x)]
        take_item_ids = [str(x) for x in take_item_ids if str(x)]

        if not to_player:
            await self.send(p.ws, {"type": "trade_result", "req_id": req_id, "ok": False, "error": "bad_request", "ts": now_ms()})
            return
        if to_player not in self.players_by_id:
            await self.send(p.ws, {"type": "trade_result", "req_id": req_id, "ok": False, "error": "target_not_online", "ts": now_ms()})
            return
        if to_player == p.player_id:
            await self.send(p.ws, {"type": "trade_result", "req_id": req_id, "ok": False, "error": "same_player", "ts": now_ms()})
            return

        a = p.player_id
        b = to_player

        async with self._trade_lock:
            ok, reason = await self._atomic_trade(a, b, give_item_ids, take_item_ids)

        if not ok:
            await self.send(p.ws, {"type": "trade_result", "req_id": req_id, "ok": False, "error": reason, "ts": now_ms()})
            return

        await self.send(p.ws, {"type": "trade_result", "req_id": req_id, "ok": True, "ts": now_ms(), "to_player_id": b})
        await self.send_player(b, {"type": "trade_completed", "from_player_id": a, "ts": now_ms(), "req_id": req_id})
        await self._push_inventory_update([a, b])

    async def _atomic_trade(self, a: str, b: str, a_gives: List[str], a_takes: List[str]) -> Tuple[bool, str]:
        item_ids = list(set(a_gives + a_takes))
        if not item_ids:
            return True, "ok"

        locks = [self.ledger._get_item_lock(i) for i in item_ids]
        unique = {}
        for iid, lk in zip(item_ids, locks):
            unique[iid] = lk
        ordered = sorted(unique.items(), key=lambda kv: kv[0])

        acquired = []
        try:
            for _, lk in ordered:
                await lk.acquire()
                acquired.append(lk)

            async with self.ledger._lock:
                for iid in a_gives:
                    if iid not in self.ledger.items:
                        return False, f"item_not_found:{iid}"
                    if self.ledger.owner.get(iid) != a:
                        return False, f"not_owner_a:{iid}"
                for iid in a_takes:
                    if iid not in self.ledger.items:
                        return False, f"item_not_found:{iid}"
                    if self.ledger.owner.get(iid) != b:
                        return False, f"not_owner_b:{iid}"

                for iid in a_gives:
                    self.ledger.owner[iid] = b
                for iid in a_takes:
                    self.ledger.owner[iid] = a

                return True, "ok"
        finally:
            for lk in reversed(acquired):
                lk.release()

    async def ws_handler(self, ws: WebSocketServerProtocol):
        try:
            async for raw in ws:
                try:
                    msg = json.loads(raw)
                    if not isinstance(msg, dict):
                        await self.send(ws, {"type": "error", "error": "bad_json", "ts": now_ms()})
                        continue
                except Exception:
                    await self.send(ws, {"type": "error", "error": "bad_json", "ts": now_ms()})
                    continue
                await self.handle_msg(ws, msg)
        finally:
            await self.unregister(ws)


async def main():
    host = "0.0.0.0"
    port = 8765
    server = GameServer()

    async with websockets.serve(
        server.ws_handler,
        host,
        port,
        max_size=2**20,
        max_queue=1024,
        ping_interval=20,
        ping_timeout=20,
        close_timeout=5,
    ):
        print(f"MMO server listening on ws://{host}:{port}")
        await asyncio.Future()


if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        pass